var NL = String.fromCharCode(10);
var now = new Date().toLocaleString('ja-JP', { timeZone: 'Asia/Tokyo' });
var raw = (($input.first() && $input.first().json && $input.first().json.stdout) || '').replace(//g, '');
var lines = raw.split(NL);
var tasks = [];
function looksGarbled(text) {
  if (!text) return false;
  return text.indexOf('Jd=~') >= 0 || text.indexOf('=?UTF-8?') >= 0 || text.indexOf('=?ISO-2022-JP?') >= 0 || text.indexOf('FbIt4F::') >= 0 || text.indexOf('0w650') >= 0;
}
for (var i = 0; i < lines.length; i++) {
  var line = lines[i].trim();
  if (!line || line.indexOf('|') !== 0) continue;
  if (line.indexOf('| ---') === 0) continue;
  if (line.indexOf('| ??? |') === 0) continue;
  var cols = line.split('|').slice(1, -1).map(function(v) { return v.trim(); });
  if (cols.length < 8) continue;
  if (cols[1] === '???' && cols[2] === '????') continue;
  if (looksGarbled(cols[1]) || looksGarbled(cols[2])) continue;
  tasks.push({
    requestDate: cols[0],
    sender: cols[1],
    request: cols[2],
    deadline: cols[3],
    response: cols[4],
    responder: cols[5],
    responseDate: cols[6],
    priority: cols[7]
  });
}
if (tasks.length && tasks[0].sender === '???') { tasks.shift(); }
var parts = ['P016 Email ToDo Daily [' + now + ']'];
if (!tasks.length) {
  parts.push('No open items found.');
} else {
  var limit = Math.min(tasks.length, 5);
  parts.push('Open items: ' + tasks.length + ' / showing: ' + limit);
  for (var j = 0; j < limit; j++) {
    var t = tasks[j];
    var req = t.request.length > 80 ? t.request.slice(0, 80) + '...' : t.request;
    var response = t.response.length > 60 ? t.response.slice(0, 60) + '...' : t.response;
    parts.push('');
    parts.push(String(j + 1) + '. Requester: ' + t.sender);
    parts.push('Request date: ' + t.requestDate + ' / Due: ' + t.deadline);
    parts.push('Task: ' + req);
    parts.push('Response: ' + response);
    parts.push('Responder: ' + t.responder + ' / Response date: ' + t.responseDate);
    parts.push('Priority: ' + t.priority);
  }
}
return [{ json: { text: parts.join(NL) } }];

